class Playground {
    async run(inputs) {
        const arr = inputs[0].split(',').map(Number);
        const target = parseInt(inputs[1]);

        this.arr.init(arr);
        this.vars.init([['left', 0], ['right', arr.length - 1], ['mid', -1]]);

        let left = 0;
        let right = arr.length - 1;

        while (left <= right) {
            let mid = Math.floor((left + right) / 2);
            this.vars.put('left', left);
            this.vars.put('right', right);
            this.vars.put('mid', mid);

            this.arr.highlightRange(left, right, '#6c8cff');
            this.arr.highlight(mid, '#ffb703');
            this.log(`Checking middle index ${mid} with value ${arr[mid]}`);
            await this.await();

            if (arr[mid] === target) {
                this.log(`Found target at index ${mid}`);
                return mid;
            } else if (arr[mid] < target) {
                left = mid + 1;
                this.log(`Target is greater, searching right half`);
            } else {
                right = mid - 1;
                this.log(`Target is smaller, searching left half`);
            }
            await this.await();
        }

        this.log('Target not found');
        return -1;
    }
}
